import type { Activity, ConsumptionEntry, FoodItem, Meal, MealLogPayload, NewConsumptionEntry } from '@motivation/shared';
import type { OFFProduct } from '../../services/openfoodfacts.service.js';
import type { FoodLogEntry } from './food-log/food-log.component.js';

export const HEALTH_EVENTS = {
    ADD_WORKOUT: 'health:add-workout',
    ADD_FOOD: 'health:add-food',
    EDIT_FOOD: 'health:edit-food',
    EDIT_WORKOUT: 'health:edit-workout',
    SCAN_BARCODE: 'health:scan-barcode',
    AI_ESTIMATE: 'health:ai-estimate',
    LOG_FOOD: 'health:log-food',
    FOOD_LOG_BACK: 'health:food-log-back',
    SELECT_LIBRARY_ITEM: 'health:select-library-item',
    SELECT_OFF_ITEM: 'health:select-off-item',
    SELECT_MEAL: 'health:select-meal',
    LOG_MEAL: 'health:log-meal',
    ADD_INGREDIENT: 'health:add-ingredient',
    PICKER_CANCEL: 'health:picker-cancel',
    LOAD_MORE_OFF: 'health:load-more-off',
    ESTIMATE_NUTRITION: 'health:estimate-nutrition',
    LOG_AI_ESTIMATE: 'health:log-ai-estimate',
} as const;

export interface HealthEventMap {
    [HEALTH_EVENTS.ADD_WORKOUT]: { date: string };
    [HEALTH_EVENTS.ADD_FOOD]: { date: string; meal: string };
    [HEALTH_EVENTS.EDIT_FOOD]: { entry: ConsumptionEntry };
    [HEALTH_EVENTS.EDIT_WORKOUT]: { activity: Activity };
    [HEALTH_EVENTS.SCAN_BARCODE]: undefined;
    [HEALTH_EVENTS.AI_ESTIMATE]: undefined;
    [HEALTH_EVENTS.LOG_FOOD]: FoodLogEntry;
    [HEALTH_EVENTS.FOOD_LOG_BACK]: undefined;
    [HEALTH_EVENTS.SELECT_LIBRARY_ITEM]: FoodItem;
    [HEALTH_EVENTS.SELECT_OFF_ITEM]: OFFProduct;
    [HEALTH_EVENTS.SELECT_MEAL]: Meal;
    [HEALTH_EVENTS.LOG_MEAL]: { meal_id: string } & MealLogPayload;
    [HEALTH_EVENTS.ADD_INGREDIENT]: { food_item: FoodItem; amount: number };
    [HEALTH_EVENTS.PICKER_CANCEL]: undefined;
    [HEALTH_EVENTS.LOAD_MORE_OFF]: undefined;
    [HEALTH_EVENTS.ESTIMATE_NUTRITION]: { description: string; image_path?: string; respondWith?: Promise<any> | null };
    [HEALTH_EVENTS.LOG_AI_ESTIMATE]: NewConsumptionEntry;
}

export type HealthEvent<K extends keyof HealthEventMap> = CustomEvent<HealthEventMap[K]>;

export function createHealthEvent<K extends keyof HealthEventMap>(
    type: K,
    detail: HealthEventMap[K]
): HealthEvent<K> {
    return new CustomEvent(type, {
        bubbles: true,
        composed: true,
        detail,
    }) as HealthEvent<K>;
}

export const createAddWorkoutEvent = (detail: HealthEventMap[typeof HEALTH_EVENTS.ADD_WORKOUT]) => createHealthEvent(HEALTH_EVENTS.ADD_WORKOUT, detail);
export const createEditWorkoutEvent = (detail: HealthEventMap[typeof HEALTH_EVENTS.EDIT_WORKOUT]) => createHealthEvent(HEALTH_EVENTS.EDIT_WORKOUT, detail);
export const createAddFoodEvent = (detail: HealthEventMap[typeof HEALTH_EVENTS.ADD_FOOD]) => createHealthEvent(HEALTH_EVENTS.ADD_FOOD, detail);
export const createEditFoodEvent = (detail: HealthEventMap[typeof HEALTH_EVENTS.EDIT_FOOD]) => createHealthEvent(HEALTH_EVENTS.EDIT_FOOD, detail);
export const createLogFoodEvent = (detail: HealthEventMap[typeof HEALTH_EVENTS.LOG_FOOD]) => createHealthEvent(HEALTH_EVENTS.LOG_FOOD, detail);
export const createLogAiEstimateEvent = (detail: HealthEventMap[typeof HEALTH_EVENTS.LOG_AI_ESTIMATE]) => createHealthEvent(HEALTH_EVENTS.LOG_AI_ESTIMATE, detail);
export const createEstimateNutritionEvent = (detail: HealthEventMap[typeof HEALTH_EVENTS.ESTIMATE_NUTRITION]) => createHealthEvent(HEALTH_EVENTS.ESTIMATE_NUTRITION, detail);
export const createScanBarcodeEvent = () => createHealthEvent(HEALTH_EVENTS.SCAN_BARCODE, undefined);
export const createAiEstimateEvent = () => createHealthEvent(HEALTH_EVENTS.AI_ESTIMATE, undefined);
export const createSelectLibraryItemEvent = (detail: HealthEventMap[typeof HEALTH_EVENTS.SELECT_LIBRARY_ITEM]) => createHealthEvent(HEALTH_EVENTS.SELECT_LIBRARY_ITEM, detail);
export const createSelectOffItemEvent = (detail: HealthEventMap[typeof HEALTH_EVENTS.SELECT_OFF_ITEM]) => createHealthEvent(HEALTH_EVENTS.SELECT_OFF_ITEM, detail);
export const createSelectMealEvent = (detail: HealthEventMap[typeof HEALTH_EVENTS.SELECT_MEAL]) => createHealthEvent(HEALTH_EVENTS.SELECT_MEAL, detail);
export const createLogMealEvent = (detail: HealthEventMap[typeof HEALTH_EVENTS.LOG_MEAL]) => createHealthEvent(HEALTH_EVENTS.LOG_MEAL, detail);
export const createAddIngredientEvent = (detail: HealthEventMap[typeof HEALTH_EVENTS.ADD_INGREDIENT]) => createHealthEvent(HEALTH_EVENTS.ADD_INGREDIENT, detail);
export const createPickerCancelEvent = () => createHealthEvent(HEALTH_EVENTS.PICKER_CANCEL, undefined);
export const createLoadMoreOffEvent = () => createHealthEvent(HEALTH_EVENTS.LOAD_MORE_OFF, undefined);
export const createFoodLogBackEvent = () => createHealthEvent(HEALTH_EVENTS.FOOD_LOG_BACK, undefined);

export type AddWorkoutEvent = HealthEvent<typeof HEALTH_EVENTS.ADD_WORKOUT>;
export type EditWorkoutEvent = HealthEvent<typeof HEALTH_EVENTS.EDIT_WORKOUT>;
export type AddFoodEvent = HealthEvent<typeof HEALTH_EVENTS.ADD_FOOD>;
export type EditFoodEvent = HealthEvent<typeof HEALTH_EVENTS.EDIT_FOOD>;
export type LogFoodEvent = HealthEvent<typeof HEALTH_EVENTS.LOG_FOOD>;
export type LogAiEstimateEvent = HealthEvent<typeof HEALTH_EVENTS.LOG_AI_ESTIMATE>;
export type EstimateNutritionEvent = HealthEvent<typeof HEALTH_EVENTS.ESTIMATE_NUTRITION>;
export type ScanBarcodeEvent = HealthEvent<typeof HEALTH_EVENTS.SCAN_BARCODE>;
export type AiEstimateEvent = HealthEvent<typeof HEALTH_EVENTS.AI_ESTIMATE>;
export type SelectLibraryItemEvent = HealthEvent<typeof HEALTH_EVENTS.SELECT_LIBRARY_ITEM>;
export type SelectOffItemEvent = HealthEvent<typeof HEALTH_EVENTS.SELECT_OFF_ITEM>;
export type SelectMealEvent = HealthEvent<typeof HEALTH_EVENTS.SELECT_MEAL>;
export type LogMealEvent = HealthEvent<typeof HEALTH_EVENTS.LOG_MEAL>;
export type AddIngredientEvent = HealthEvent<typeof HEALTH_EVENTS.ADD_INGREDIENT>;
export type PickerCancelEvent = HealthEvent<typeof HEALTH_EVENTS.PICKER_CANCEL>;
export type LoadMoreOffEvent = HealthEvent<typeof HEALTH_EVENTS.LOAD_MORE_OFF>;
export type FoodLogBackEvent = HealthEvent<typeof HEALTH_EVENTS.FOOD_LOG_BACK>;

declare global {
    interface HTMLElementEventMap {
        [HEALTH_EVENTS.ADD_WORKOUT]: AddWorkoutEvent;
        [HEALTH_EVENTS.ADD_FOOD]: AddFoodEvent;
        [HEALTH_EVENTS.EDIT_FOOD]: EditFoodEvent;
        [HEALTH_EVENTS.EDIT_WORKOUT]: EditWorkoutEvent;
        [HEALTH_EVENTS.SCAN_BARCODE]: ScanBarcodeEvent;
        [HEALTH_EVENTS.AI_ESTIMATE]: AiEstimateEvent;
        [HEALTH_EVENTS.LOG_FOOD]: LogFoodEvent;
        [HEALTH_EVENTS.FOOD_LOG_BACK]: FoodLogBackEvent;
        [HEALTH_EVENTS.SELECT_LIBRARY_ITEM]: SelectLibraryItemEvent;
        [HEALTH_EVENTS.SELECT_OFF_ITEM]: SelectOffItemEvent;
        [HEALTH_EVENTS.SELECT_MEAL]: SelectMealEvent;
        [HEALTH_EVENTS.LOG_MEAL]: LogMealEvent;
        [HEALTH_EVENTS.ADD_INGREDIENT]: AddIngredientEvent;
        [HEALTH_EVENTS.PICKER_CANCEL]: PickerCancelEvent;
        [HEALTH_EVENTS.LOAD_MORE_OFF]: LoadMoreOffEvent;
        [HEALTH_EVENTS.ESTIMATE_NUTRITION]: EstimateNutritionEvent;
        [HEALTH_EVENTS.LOG_AI_ESTIMATE]: LogAiEstimateEvent;
    }
}
